body:
The below test, rewritten from UVM tests/99compat/7520_compat_packer and about 6 similar tests, fails with:

```
%Error: t/t_0.v:22:42: Syntax error: Not expecting CLASSREFDTYPE under a DOT in dotted expression
   22 |     typedef object_registry#(c_pkg::compat_packer,"c_pkg::compat_packer") type_id;
      |                                     ^~~~~~~~~~~~~
        t/t_0.v:22:42: ... Resolving this reference
   22 |     typedef object_registry#(c_pkg::compat_packer,"c_pkg::compat_packer") type_id;
      |                                     ^~~~~~~~~~~~~
```

```
package pkg;
  class object_registry #(
      type T = int
  );
  endclass

  class packer;
    typedef object_registry#(packer) type_id;
  endclass
endpackage

package c_pkg;
  import pkg::*;
  class compat_packer extends pkg::packer;
    typedef object_registry#(c_pkg::compat_packer) type_id;
  endclass
endpackage

import pkg::*;
import c_pkg::*;

module t;
  initial begin
    compat_packer c;
    c = new();
    $finish;
  end
endmodule
```

